  '[{"text":"Send brand assets, social media templates, and video lower thirds for team review and feedback (02:40)","completed":false},{"text":"Provide side-by-side font comparison samples to Jane and Christina for review (07:42)","completed":false},{"text":"Send samples of line drawings and icons to the team to build out brand asset library (16:33)","completed":false},{"text":"Deliver all current assets for feedback; continue development of variations as needed (21:36)","completed":false},{"text":"Set up marketing@poncebank.net login user in HubSpot for marketing team access (43:00)","completed":false},{"text":"Grant super admin access on Meta (Facebook) side for HubSpot LinkedIn connection (22:44)","completed":false},{"text":"Ping Jane regarding LinkedIn Business Manager setup confirmation (25:25)","completed":false},{"text":"Handle Twitter profile access and invite Marketers in Demand team (26:13)","completed":false},{"text":"Coordinate with Ashley and Gabe regarding meeting rescheduling and HubSpot sandbox user setup (34:51)","completed":false},{"text":"Provide attestation document templates or help with documents to support compliance requirements (37:47)","completed":false}]'::jsonb,
