  '[{"text":"Organize and consolidate all feedback including brand guidelines and send updated version to Kylie for review (05:50)","completed":false},{"text":"Increase homepage text sizes and adjust header letter spacing per Kylie’s notes (11:50)","completed":false},{"text":"Adjust homepage topography background desaturation and update orange accent line animation to lighter or dashed alternative (08:30)","completed":false},{"text":"Coordinate with Jenny and Nina to align deliverable templates (PowerPoints, social media, PDF layouts) and assess gaps (05:00)","completed":false},{"text":"Provide email recap summarizing all discussed feedback and next steps to Kylie (30:45)","completed":false},{"text":"Plan potential follow-up huddle by week’s end to review feedback progress (31:10)","completed":false},{"text":"Resend annotated brand guideline PDF if needed and provide headshots for quotes (03:00)","completed":false},{"text":"Share Google Doc and email detailed Tier 2 guide edits and ebook design notes with team (09:50)","completed":false},{"text":"Provide final copy for chemical product page for review by Wednesday or Thursday (30:10)","completed":false},{"text":"Load latest annotated brand guidelines with Kylie’s comments into a single markup file for team review (05:50)","completed":false},{"text":"Integrate homepage and waste page design changes including carousel for dual product images and updated animations (26:50)","completed":false},{"text":"Provide support on finalizing chemical product images and copy collaboration with designer (28:50)","completed":false},{"text":"Assist with clarifying product capabilities messaging and image requirements for features sections (29:00)","completed":false}]'::jsonb,
