"speaker_name":"Rob"},{"text":"Yeah.","index":521,"end_time":1752.98,"speaker_id":1,"start_time":1752.74,"speaker_name":"Tristan Pelligrino"},{"text":"What is this?","index":522,"end_time":1753.34,"speaker_id":1,"start_time":1752.98,"speaker_name":"Tristan Pelligrino"},{"text":"This one doesn''t have.","index":523,"end_time":1754.34,"speaker_id":1,"start_time":1753.34,"speaker_name":"Tristan Pelligrino"},{"text":"Maybe that''s an old one.","index":524,"end_time":1756.42,"speaker_id":0,"start_time":1755.06,"speaker_name":"Rob"},{"text":"Go to it.","index":525,"end_time":1756.9,"speaker_id":0,"start_time":1756.42,"speaker_name":"Rob"},{"text":"Yeah.","index":526,"end_time":1757.3,"speaker_id":1,"start_time":1756.9,"speaker_name":"Tristan Pelligrino"},{"text":"Let''s see if that''s even published.","index":527,"end_time":1760.58,"speaker_id":1,"start_time":1758.82,"speaker_name":"Tristan Pelligrino"},{"text":"100.","index":528,"end_time":1762.9,"speaker_id":1,"start_time":1762.34,"speaker_name":"Tristan Pelligrino"},{"text":"We''ll do one of these.","index":529,"end_time":1774.59,"speaker_id":1,"start_time":1773.71,"speaker_name":"Tristan Pelligrino"},{"text":"Yes.","index":530,"end_time":1776.07,"speaker_id":0,"start_time":1775.55,"speaker_name":"Rob"},{"text":"I guess work with rugged maybe.","index":531,"end_time":1778.03,"speaker_id":0,"start_time":1776.07,"speaker_name":"Rob"},{"text":"So you see these like section layouts and it''s like layout one, layout two etc.","index":532,"end_time":1788.43,"speaker_id":0,"start_time":1783.55,"speaker_name":"Rob"},{"text":"Yeah.","index":533,"end_time":1789.07,"speaker_id":1,"start_time":1788.59,"speaker_name":"Tristan Pelligrino"},{"text":"Where are those housed?","index":534,"end_time":1790.75,"speaker_id":0,"start_time":1789.39,"speaker_name":"Rob"},{"text":"Like these.","index":535,"end_time":1792.59,"speaker_id":1,"start_time":1790.91,"speaker_name":"Tristan Pelligrino"},{"text":"This is advanced custom fields.","index"